func csilDecTranslationsResponse(csilRoot cborValue) (TranslationsResponse, error) {
	var csilOut TranslationsResponse
	{
		csilField, csilErr := cborRequire(csilRoot, "locale")
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilVal, csilErr := (cborAsText)(csilField)
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilOut.Locale = csilVal
	}
	{
		csilField, csilErr := cborRequire(csilRoot, "available_locales")
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilVal, csilErr := (func(csilV cborValue) ([]string, error) { return cborDecArray(csilV, cborAsText) })(csilField)
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilOut.AvailableLocales = csilVal
	}
	{
		csilField, csilErr := cborRequire(csilRoot, "messages")
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilVal, csilErr := (func(csilV cborValue) (LocaleMessages, error) {
			csilInner, csilErr := (func(csilV cborValue) (map[string]string, error) { return cborDecMap(csilV, cborAsText, cborAsText) })(csilV)
			return LocaleMessages(csilInner), csilErr
		})(csilField)
		if csilErr != nil {
			return csilOut, csilErr
		}
		csilOut.Messages = csilVal
	}
	return csilOut, nil
}

