// csilEncCheckValue encodes a CheckValue union as a tagged sum [variant_index, value].
func csilEncCheckValue(csilV CheckValue) cborValue {
	switch csilX := csilV.(type) {
	case string:
		return cborArray{cborUint(0), cborText(csilX)}
	case int64:
		return cborArray{cborUint(1), cborInt(csilX)}
	case float64:
		return cborArray{cborUint(2), cborFloat(csilX)}
	default:
		return cborNull{}
	}
}

// csilDecCheckValue decodes a tagged sum [variant_index, value] into a CheckValue union.
func csilDecCheckValue(csilV cborValue) (CheckValue, error) {
	csilArr, csilOk := csilV.(cborArray)
	if !csilOk || len(csilArr) != 2 {
		var csilZero CheckValue
		return csilZero, fmt.Errorf("csil cbor: CheckValue union expects a 2-element array")
	}
	csilIdx, csilIdxErr := cborAsU64(csilArr[0])
	if csilIdxErr != nil {
		var csilZero CheckValue
		return csilZero, csilIdxErr
	}
	switch csilIdx {
	case 0:
		csilVal, csilErr := (cborAsText)(csilArr[1])
		return csilVal, csilErr
	case 1:
		csilVal, csilErr := (cborAsI64)(csilArr[1])
		return csilVal, csilErr
	case 2:
		csilVal, csilErr := (cborAsF64)(csilArr[1])
		return csilVal, csilErr
	default:
		var csilZero CheckValue
		return csilZero, fmt.Errorf("csil cbor: unknown CheckValue variant %d", csilIdx)
	}
}
